/// Apply all macros to a theory in place.
///
/// Thin staging glue over the clean-room staged macro expander
/// [`crate::macros::expand_staged`]: it expands ordinary lemmas, restrictions,
/// predicates, processes, and the primary rule form (plus bare-nullary uses),
/// carries derived variant / left-right rule forms and acc-lemma / case-test
/// formulas through untouched, and retains the `macros:` declarations in place.
/// A theory with no macros is returned unchanged.
pub fn expand_theory_macros(thy: &mut p::Theory) {
    *thy = crate::macros::expand_staged(thy);
}

/// Clone a parser theory and expand its macros (staged).  Used for the WF
/// re-checks (batch and web load paths) that must see macro-expanded rules.
pub fn macro_expanded_clone(parsed: &p::Theory) -> p::Theory {
    crate::macros::expand_staged(parsed)
}

