1	//! Stream-aware output framing around opaque theory payloads.
2	//!
3	//! A batch run writes to two independent streams (see `workspace/BEHAVIOR.md`
4	//! §10). This module models which text lands on which stream and assembles both
5	//! byte-exactly. The theory pretty-print (`theory <name> … end`, including any
6	//! `WARNING:` block and the `Generated from:` comment) is an opaque payload slot;
7	//! everything around it — the maude preamble, the per-theory progress markers, and
8	//! the "summary of summaries" block — is built here.
9	//!
10	//! Stream assignment: the maude preamble and progress markers go to stderr;
11	//! payloads and the summary block go to stdout.
12	
13	use crate::stream::Streams;
14	use crate::version::{maude_preamble, MaudeInfo};
15	
16	/// Width of the `=` rule that brackets the summary block (observed: 78).
17	const RULE_WIDTH: usize = 78;
18	
19	/// Per-theory progress phases, in the order printed for a fully closed theory.
20	#[derive(Debug, Clone, Copy)]
21	pub enum Phase {
22	    Loaded,
23	    Translated,
24	    DerivationChecksStarted,
25	    DerivationChecksEnded,
26	    Closed,
27	}
28	
29	impl Phase {
30	    fn text(self) -> &'static str {
31	        match self {
32	            Phase::Loaded => "Theory loaded",
33	            Phase::Translated => "Theory translated",
34	            Phase::DerivationChecksStarted => "Derivation checks started",
35	            Phase::DerivationChecksEnded => "Derivation checks ended",
36	            Phase::Closed => "Theory closed",
37	        }
38	    }
39	}
40	
41	/// The five progress phases a closed theory reports.
42	pub const CLOSED_PHASES: [Phase; 5] = [
43	    Phase::Loaded,
44	    Phase::Translated,
45	    Phase::DerivationChecksStarted,
46	    Phase::DerivationChecksEnded,
47	    Phase::Closed,
48	];
49	
50	/// One progress line: `[Theory <name>] <phase>\n` (stderr).
51	pub fn progress_line(theory: &str, phase: Phase) -> String {
52	    format!("[Theory {}] {}\n", theory, phase.text())
53	}
54	
55	fn progress_block(theory: &str, phases: &[Phase]) -> String {
56	    phases.iter().map(|p| progress_line(theory, *p)).collect()
57	}
58	
59	/// Whether a lemma quantifies over all traces or asserts an existing trace.
60	#[derive(Debug, Clone, Copy)]
61	pub enum TraceKind {
62	    AllTraces,
63	    ExistsTrace,
64	}
65	
66	impl TraceKind {
67	    fn text(self) -> &'static str {
68	        match self {
69	            TraceKind::AllTraces => "all-traces",
70	            TraceKind::ExistsTrace => "exists-trace",
71	        }
72	    }
73	}
74	
75	/// Per-lemma verdict. The printed text of a falsified verdict depends on the
76	/// lemma's [`TraceKind`] (see [`LemmaOutcome::result_text`]); verified and
77	/// incomplete verdicts print the same for both kinds.
78	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
79	pub enum LemmaResult {
80	    Verified,
81	    Falsified,
82	    AnalysisIncomplete,
83	}
84	
85	/// One lemma's verdict line in a theory's summary body:
86	/// `<name> (<kind>): <verdict> (<steps> steps)`.
87	#[derive(Debug, Clone)]
88	pub struct LemmaOutcome {
89	    pub name: String,
90	    pub kind: TraceKind,
91	    pub result: LemmaResult,
92	    /// The `<N>` in `(<N> steps)` — the number of proof steps explored (also the
93	    /// value shown for bounded/incomplete analyses, reflecting the explored depth).
94	    pub steps: u64,
95	}
96	
97	impl LemmaOutcome {
98	    /// The verdict phrase. `verified` and `analysis incomplete` are uniform; a
99	    /// `falsified` verdict reads `falsified - found trace` for an all-traces lemma
100	    /// (a counter-example was produced) and `falsified - no trace found` for an
101	    /// exists-trace lemma (no witnessing trace exists).
102	    fn result_text(&self) -> &'static str {
103	        match self.result {
104	            LemmaResult::Verified => "verified",
105	            LemmaResult::AnalysisIncomplete => "analysis incomplete",
106	            LemmaResult::Falsified => match self.kind {
107	                TraceKind::AllTraces => "falsified - found trace",
108	                TraceKind::ExistsTrace => "falsified - no trace found",
109	            },
110	        }
111	    }
112	
113	    /// The single result line, without its `  ` indent.
114	    fn line(&self) -> String {
115	        format!(
116	            "{} ({}): {} ({} steps)",
117	            self.name,
118	            self.kind.text(),
119	            self.result_text(),
120	            self.steps
121	        )
122	    }
123	}
124	
125	/// Prefix shared by the `WARNING:` line and its aligned advisory continuation.
126	const WARNING_PREFIX: &str = "  WARNING: ";
127	
128	/// The wellformedness-warning heading of a theory's summary body. Present only
129	/// when at least one wellformedness check failed.
130	#[derive(Debug, Clone)]
131	pub struct WarningSummary {
132	    /// The `<N>` in `WARNING: <N> wellformedness check failed!` (the noun stays
133	    /// singular "check" regardless of `<N>`).
134	    pub failed_checks: u64,
135	    /// Whether the advisory line `The analysis results might be wrong!` follows
136	    /// the count line. Observed: emitted exactly when the run is a proving run
137	    /// (`--prove`), independent of how many lemmas were actually proved (a
138	    /// proving run with zero matched lemmas still emits it; a plain analyze run
139	    /// never does).
140	    pub analysis_maybe_wrong: bool,
141	}
142	
143	impl WarningSummary {
144	    /// The warning heading (one or two lines, each `\n`-terminated). The advisory
145	    /// continuation is left-padded to align under the text after `WARNING: `.
146	    fn render(&self) -> String {
147	        let mut s = String::new();
148	        s.push_str(WARNING_PREFIX);
149	        s.push_str(&format!("{} wellformedness check failed!\n", self.failed_checks));
150	        if self.analysis_maybe_wrong {
151	            for _ in 0..WARNING_PREFIX.len() {
152	                s.push(' ');
153	            }
154	            s.push_str("The analysis results might be wrong!\n");
155	        }
156	        s
157	    }
158	}
159	
160	/// One theory's contribution to the "summary of summaries" block.
161	#[derive(Debug, Clone)]
162	pub struct Summary {
163	    /// The `analyzed:` path, echoed exactly as given on the command line.
164	    pub analyzed: String,
165	    /// The `output:` path, present only when the theory was written to a file
166	    /// (`-o`/`-O`).
167	    pub output: Option<String>,
168	    /// Rendered as seconds with two decimals (e.g. `0.39s`).
169	    pub processing_time: f64,
170	    /// The wellformedness-warning heading, when any check failed.
171	    pub warnings: Option<WarningSummary>,
172	    /// The per-lemma verdict lines, in report order.
173	    pub lemmas: Vec<LemmaOutcome>,
174	}
175	
176	impl Summary {
177	    /// The theory's block: the `analyzed:` header, a blank line, the aligned
178	    /// key/value rows (`output:` when present, then `processing time:`), then the
179	    /// body. The body opens with a `  ` (two-space) line and carries up to two
180	    /// sections — the warning heading and the lemma lines, in that order — each
181	    /// section preceded by a `  ` line (so a `  ` line also separates the two when
182	    /// both are present).
183	    fn render_block(&self) -> String {
184	        let mut b = String::new();
185	        b.push_str(&format!("analyzed: {}\n", self.analyzed));
186	        b.push('\n');
187	
188	        // Aligned key/value rows: labels right-padded to the widest label, then a
189	        // single space, so every value starts at the same column.
190	        let mut rows: Vec<(&str, String)> = Vec::new();
191	        if let Some(o) = &self.output {
192	            rows.push(("output:", o.clone()));
193	        }
194	        rows.push(("processing time:", format!("{:.2}s", self.processing_time)));
195	        let width = rows.iter().map(|(label, _)| label.len()).max().unwrap_or(0);
196	        for (label, value) in &rows {
197	            b.push_str("  ");
198	            b.push_str(label);
199	            for _ in 0..(width - label.len()) {
200	                b.push(' ');
201	            }
202	            b.push(' ');
203	            b.push_str(value);
204	            b.push('\n');
205	        }
206	
207	        // Body: an opening `  ` (two-space) line, then the present sections joined
208	        // by another `  ` line — the warning heading first, then the lemma lines.
209	        b.push_str("  \n");
210	        let mut sections: Vec<String> = Vec::new();
211	        if let Some(w) = &self.warnings {
212	            sections.push(w.render());
213	        }
214	        if !self.lemmas.is_empty() {
215	            let mut lines = String::new();
216	            for l in &self.lemmas {
217	                lines.push_str("  ");
218	                lines.push_str(&l.line());
219	                lines.push('\n');
220	            }
221	            sections.push(lines);
222	        }
223	        b.push_str(&sections.join("  \n"));
224	        b
225	    }
226	}
227	
228	/// The full "summary of summaries" section as it appears on stdout: a leading
229	/// blank line (the payload/summary separator, always present), the top `=` rule,
230	/// the header, each theory block preceded by a blank line, a trailing blank line,
231	/// and the bottom rule.
232	pub fn render_summary(summaries: &[Summary]) -> String {
233	    let rule = "=".repeat(RULE_WIDTH);
234	    let mut out = String::new();
235	    out.push('\n');
236	    out.push_str(&rule);
237	    out.push('\n');
238	    out.push_str("summary of summaries:\n");
239	    for s in summaries {
240	        out.push('\n');
241	        out.push_str(&s.render_block());
242	    }
243	    out.push('\n');
244	    out.push_str(&rule);
245	    out.push('\n');
246	    out
247	}
248	
249	/// A theory processed by a closed batch run.
250	#[derive(Debug, Clone)]
251	pub struct BatchTheory {
252	    /// Name used in the `[Theory <name>]` progress markers (stderr).
253	    pub name: String,
254	    /// The printed theory payload (stdout), or `None` when it was written to an
255	    /// output file instead.
256	    pub payload: Option<String>,
257	    /// Further progress lines the engine emitted for this theory after the five
258	    /// closed phases (stderr), verbatim and newline-terminated. Empty for a plain
259	    /// analyze run; under `--prove` it carries the `[Saturating Sources] …` lines.
260	    pub extra_progress: String,
261	    /// This theory's summary contribution (stdout).
262	    pub summary: Summary,
263	}
264	
265	/// A closed batch run over one or more theories.
266	///
267	/// stderr: the maude preamble, then per theory the five progress markers followed
268	/// by any extra engine progress. stdout: the printed payloads (in order), then one
269	/// combined summary block.
