114	/// One theory's contribution to the "summary of summaries" block.
115	#[derive(Debug, Clone)]
116	pub struct Summary {
117	    /// The `analyzed:` path, echoed exactly as given on the command line.
118	    pub analyzed: String,
119	    /// The `output:` path, present only when the theory was written to a file
120	    /// (`-o`/`-O`).
121	    pub output: Option<String>,
122	    /// Rendered as seconds with two decimals (e.g. `0.39s`).
123	    pub processing_time: f64,
124	    pub entries: Vec<SummaryEntry>,
125	}
