127	impl Summary {
128	    /// The theory's block: the `analyzed:` header, a blank line, the aligned
129	    /// key/value rows (`output:` when present, then `processing time:`), the
130	    /// two-space separator line, then one line per entry.
131	    fn render_block(&self) -> String {
132	        let mut b = String::new();
133	        b.push_str(&format!("analyzed: {}\n", self.analyzed));
134	        b.push('\n');
135	
136	        // Aligned key/value rows: labels right-padded to the widest label, then a
137	        // single space, so every value starts at the same column.
138	        let mut rows: Vec<(&str, String)> = Vec::new();
139	        if let Some(o) = &self.output {
140	            rows.push(("output:", o.clone()));
141	        }
142	        rows.push(("processing time:", format!("{:.2}s", self.processing_time)));
143	        let width = rows.iter().map(|(label, _)| label.len()).max().unwrap_or(0);
144	        for (label, value) in &rows {
145	            b.push_str("  ");
146	            b.push_str(label);
147	            for _ in 0..(width - label.len()) {
148	                b.push(' ');
149	            }
150	            b.push(' ');
151	            b.push_str(value);
152	            b.push('\n');
153	        }
154	
155	        b.push_str("  \n"); // literal two-space separator line
156	        for e in &self.entries {
157	            b.push_str(&format!("  {}\n", e.text()));
158	        }
159	        b
160	    }
161	}
