163	/// The full "summary of summaries" section as it appears on stdout: a leading
164	/// blank line (the payload/summary separator, always present), the top `=` rule,
165	/// the header, each theory block preceded by a blank line, a trailing blank line,
166	/// and the bottom rule.
167	pub fn render_summary(summaries: &[Summary]) -> String {
168	    let rule = "=".repeat(RULE_WIDTH);
169	    let mut out = String::new();
170	    out.push('\n');
171	    out.push_str(&rule);
172	    out.push('\n');
173	    out.push_str("summary of summaries:\n");
174	    for s in summaries {
175	        out.push('\n');
176	        out.push_str(&s.render_block());
177	    }
178	    out.push('\n');
179	    out.push_str(&rule);
180	    out.push('\n');
181	    out
182	}
