435	/// Expand the positional input list into a list of `.spthy` files.
436	/// Haskell's interactive mode takes a single working directory; we
437	/// accept either a directory (whose `.spthy` files we glob) or any
438	/// number of `.spthy` files (the path Tamarin batch mode uses).
439	fn collect_theory_paths(in_files: &[String]) -> Result<Vec<std::path::PathBuf>, RunError> {
440	    let mut out: Vec<PathBuf> = Vec::new();
441	    for f in in_files {
442	        let p = PathBuf::from(f);
443	        if p.is_dir() {
444	            let entries = std::fs::read_dir(&p).map_err(|e| {
445	                RunError(format!("could not read directory {}: {}", p.display(), e))
446	            })?;
447	            for e in entries.flatten() {
448	                let ep = e.path();
449	                if ep.extension().and_then(|s| s.to_str()) == Some("spthy") {
450	                    out.push(ep);
451	                }
452	            }
453	        } else {
454	            out.push(p);
455	        }
456	    }
457	    out.sort();
458	    Ok(out)
459	}
