461	/// Best-effort: locate the bundled `frontend/dist/` sibling of `data/`.
462	/// Returns None if not found — the server tolerates this and just
463	/// won't serve the frontend assets.
464	fn guess_frontend_dist(data_dir: &std::path::Path) -> Option<std::path::PathBuf> {
465	    let parent = data_dir.parent()?;
466	    let candidate = parent.join("frontend").join("dist");
467	    if candidate.is_dir() {
468	        return Some(candidate);
469	    }
470	    None
471	}
