534	/// HS shows the maude tool's basename when the user didn't pass
535	/// `--maude-path`, and the full path when they did (Console.hs:150).  We
536	/// can't re-introspect the flag downstream, so we key off `args.maude_path`
537	/// being `None` (the default) vs `Some` (user-supplied).
538	fn maude_display_name(args: &Args) -> String {
539	    let raw_path = args.maude_path.clone().unwrap_or_else(default_maude_path);
540	    if args.maude_path.is_some() {
541	        raw_path
542	    } else {
543	        std::path::Path::new(&raw_path)
544	            .file_name()
545	            .and_then(|s| s.to_str())
546	            .unwrap_or(&raw_path)
547	            .to_string()
548	    }
549	}
