1556	/// Emit `body` to `--output` / `-O` / stdout.
1557	fn emit_output(args: &Args, in_file: &str, body: &str) -> Result<(), RunError> {
1558	    if let Some(out) = out_path_for(args, in_file) {
1559	        // Ensure parent dir exists.
1560	        if let Some(parent) = std::path::Path::new(&out).parent() {
1561	            if !parent.as_os_str().is_empty() {
1562	                fs::create_dir_all(parent).map_err(|e| {
1563	                    RunError(format!("failed to create {}: {}", parent.display(), e))
1564	                })?;
1565	            }
1566	        }
1567	        fs::write(&out, body)
1568	            .map_err(|e| RunError(format!("failed to write {}: {}", out, e)))?;
1569	    } else {
1570	        // stdout
1571	        print!("{}", body);
1572	    }
1573	    Ok(())
1574	}
