1596	/// Count proof-tree nodes — the number of `LNode` constructors in the
1597	/// proof tree.  Each `step` in the proof's textual form (a `simplify` /
1598	/// `solve(...) case X` / `qed` / `SOLVED` annotation) corresponds to one
1599	/// ProofNode.  Mirrors HS's `foldProof proofStepSummary` (which sums
1600	/// `const (Sum 1)` over every ProofStep — ClosedTheory.hs:484,491 via
1601	/// `foldProof`, Theory/Proof.hs:358).
1602	fn count_proof_steps(node: &tamarin_theory::constraint::solver::search::ProofNode) -> usize {
1603	    1 + node.children.values().map(count_proof_steps).sum::<usize>()
1604	}
