input.content:
//! Stream-aware output framing around opaque theory payloads.
//!
//! A batch run writes to two independent streams (see `workspace/BEHAVIOR.md`
//! §10). This module models which text lands on which stream and assembles both
//! byte-exactly. The theory pretty-print (`theory <name> … end`, including any
//! `WARNING:` block and the `Generated from:` comment) is an opaque payload slot;
//! everything around it — the maude preamble, the per-theory progress markers, and
//! the "summary of summaries" block — is built here.
//!
//! Stream assignment: the maude preamble and progress markers go to stderr;
//! payloads and the summary block go to stdout.

use super::stream::Streams;
use super::version::{maude_preamble, MaudeInfo};

/// Width of the `=` rule that brackets the summary block (observed: 78).
const RULE_WIDTH: usize = 78;

/// Per-theory progress phases, in the order printed for a fully closed theory.
#[derive(Debug, Clone, Copy)]
pub enum Phase {
    Loaded,
    Translated,
    DerivationChecksStarted,
    DerivationChecksEnded,
    Closed,
}

impl Phase {
    fn text(self) -> &'static str {
        match self {
            Phase::Loaded => "Theory loaded",
            Phase::Translated => "Theory translated",
            Phase::DerivationChecksStarted => "Derivation checks started",
            Phase::DerivationChecksEnded => "Derivation checks ended",
            Phase::Closed => "Theory closed",
        }
    }
}

/// The five progress phases a closed theory reports.
pub const CLOSED_PHASES: [Phase; 5] = [
    Phase::Loaded,
    Phase::Translated,
    Phase::DerivationChecksStarted,
    Phase::DerivationChecksEnded,
    Phase::Closed,
];

/// One progress line: `[Theory <name>] <phase>\n` (stderr).
pub fn progress_line(theory: &str, phase: Phase) -> String {
    format!("[Theory {}] {}\n", theory, phase.text())
}

fn progress_block(theory: &str, phases: &[Phase]) -> String {
    phases.iter().map(|p| progress_line(theory, *p)).collect()
}

/// Whether a lemma quantifies over all traces or asserts an existing trace.
#[derive(Debug, Clone, Copy)]
pub enum TraceKind {
    AllTraces,
    ExistsTrace,
}

impl TraceKind {
    fn text(self) -> &'static str {
        match self {
            TraceKind::AllTraces => "all-traces",
            TraceKind::ExistsTrace => "exists-trace",
        }
    }
}

/// Per-lemma verdict. The printed text of a falsified verdict depends on the
/// lemma's [`TraceKind`] (see [`LemmaOutcome::result_text`]); verified and
/// incomplete verdicts print the same for both kinds.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum LemmaResult {
    Verified,
    Falsified,
    AnalysisIncomplete,
}

/// One lemma's verdict line in a theory's summary body:
/// `<name> (<kind>): <verdict> (<steps> steps)`.
#[derive(Debug, Clone)]
pub struct LemmaOutcome {
    pub name: String,
    pub kind: TraceKind,
    pub result: LemmaResult,
    /// The `<N>` in `(<N> steps)` — the number of proof steps explored (also the
    /// value shown for bounded/incomplete analyses, reflecting the explored depth).
    pub steps: u64,
}

impl LemmaOutcome {
    /// The verdict phrase. `verified` and `analysis incomplete` are uniform; a
    /// `falsified` verdict reads `falsified - found trace` for an all-traces lemma
    /// (a counter-example was produced) and `falsified - no trace found` for an
    /// exists-trace lemma (no witnessing trace exists).
    fn result_text(&self) -> &'static str {
        match self.result {
            LemmaResult::Verified => "verified",
            LemmaResult::AnalysisIncomplete => "analysis incomplete",
            LemmaResult::Falsified => match self.kind {
                TraceKind::AllTraces => "falsified - found trace",
                TraceKind::ExistsTrace => "falsified - no trace found",
            },
        }
    }

    /// The single result line, without its `  ` indent.
    fn line(&self) -> String {
        format!(
            "{} ({}): {} ({} steps)",
            self.name,
            self.kind.text(),
            self.result_text(),
            self.steps
        )
    }
}

/// Prefix shared by the `WARNING:` line and its aligned advisory continuation.
const WARNING_PREFIX: &str = "  WARNING: ";

/// The wellformedness-warning heading of a theory's summary body. Present only
/// when at least one wellformedness check failed.
#[derive(Debug, Clone)]
pub struct WarningSummary {
    /// The `<N>` in `WARNING: <N> wellformedness check failed!` (the noun stays
    /// singular "check" regardless of `<N>`).
    pub failed_checks: u64,
    /// Whether the advisory line `The analysis results might be wrong!` follows
    /// the count line. Observed: emitted exactly when the run is a proving run
    /// (`--prove`), independent of how many lemmas were actually proved (a
    /// proving run with zero matched lemmas still emits it; a plain analyze run
    /// never does).
    pub analysis_maybe_wrong: bool,
}

impl WarningSummary {
    /// The warning heading (one or two lines, each `\n`-terminated). The advisory
    /// continuation is left-padded to align under the text after `WARNING: `.
    fn render(&self) -> String {
        let mut s = String::new();
        s.push_str(WARNING_PREFIX);
        s.push_str(&format!("{} wellformedness check failed!\n", self.failed_checks));
        if self.analysis_maybe_wrong {
            for _ in 0..WARNING_PREFIX.len() {
                s.push(' ');
            }
            s.push_str("The analysis results might be wrong!\n");
        }
        s
    }
}

/// One theory's contribution to the "summary of summaries" block.
#[derive(Debug, Clone)]
pub struct Summary {
    /// The `analyzed:` path, echoed exactly as given on the command line.
    pub analyzed: String,
    /// The `output:` path, present only when the theory was written to a file
    /// (`-o`/`-O`).
    pub output: Option<String>,
    /// Rendered as seconds with two decimals (e.g. `0.39s`).
    pub processing_time: f64,
    /// The wellformedness-warning heading, when any check failed.
    pub warnings: Option<WarningSummary>,
    /// The per-lemma verdict lines, in report order.
    pub lemmas: Vec<LemmaOutcome>,
}

impl Summary {
    /// The theory's block: the `analyzed:` header, a blank line, the aligned
    /// key/value rows (`output:` when present, then `processing time:`), then the
    /// body. The body opens with a `  ` (two-space) line and carries up to two
    /// sections — the warning heading and the lemma lines, in that order — each
    /// section preceded by a `  ` line (so a `  ` line also separates the two when
    /// both are present).
    fn render_block(&self) -> String {
        let mut b = String::new();
        b.push_str(&format!("analyzed: {}\n", self.analyzed));
        b.push('\n');

        // Aligned key/value rows: labels right-padded to the widest label, then a
        // single space, so every value starts at the same column.
        let mut rows: Vec<(&str, String)> = Vec::new();
        if let Some(o) = &self.output {
            rows.push(("output:", o.clone()));
        }
        rows.push(("processing time:", format!("{:.2}s", self.processing_time)));
        let width = rows.iter().map(|(label, _)| label.len()).max().unwrap_or(0);
        for (label, value) in &rows {
            b.push_str("  ");
            b.push_str(label);
            for _ in 0..(width - label.len()) {
                b.push(' ');
            }
            b.push(' ');
            b.push_str(value);
            b.push('\n');
        }

        // Body: an opening `  ` (two-space) line, then the present sections joined
        // by another `  ` line — the warning heading first, then the lemma lines.
        b.push_str("  \n");
        let mut sections: Vec<String> = Vec::new();
        if let Some(w) = &self.warnings {
            sections.push(w.render());
        }
        if !self.lemmas.is_empty() {
            let mut lines = String::new();
            for l in &self.lemmas {
                lines.push_str("  ");
                lines.push_str(&l.line());
                lines.push('\n');
            }
            sections.push(lines);
        }
        b.push_str(&sections.join("  \n"));
        b
    }
}

/// The full "summary of summaries" section as it appears on stdout: a leading
/// blank line (the payload/summary separator, always present), the top `=` rule,
/// the header, each theory block preceded by a blank line, a trailing blank line,
/// and the bottom rule.
pub fn render_summary(summaries: &[Summary]) -> String {
    let rule = "=".repeat(RULE_WIDTH);
    let mut out = String::new();
    out.push('\n');
    out.push_str(&rule);
    out.push('\n');
    out.push_str("summary of summaries:\n");
    for s in summaries {
        out.push('\n');
        out.push_str(&s.render_block());
    }
    out.push('\n');
    out.push_str(&rule);
    out.push('\n');
    out
}

/// A theory processed by a closed batch run.
#[derive(Debug, Clone)]
pub struct BatchTheory {
    /// Name used in the `[Theory <name>]` progress markers (stderr).
    pub name: String,
    /// The printed theory payload (stdout), or `None` when it was written to an
    /// output file instead.
    pub payload: Option<String>,
    /// Further progress lines the engine emitted for this theory after the five
    /// closed phases (stderr), verbatim and newline-terminated. Empty for a plain
    /// analyze run; under `--prove` it carries the `[Saturating Sources] …` lines.
    pub extra_progress: String,
    /// This theory's summary contribution (stdout).
    pub summary: Summary,
}

/// A closed batch run over one or more theories.
///
/// stderr: the maude preamble, then per theory the five progress markers followed
/// by any extra engine progress. stdout: the printed payloads (in order), then one
/// combined summary block.
pub fn frame_batch(maude: &MaudeInfo, theories: &[BatchTheory]) -> Streams {
    let mut s = Streams::default();
    s.err.push_str(&maude_preamble(maude));
    for t in theories {
        s.err.push_str(&progress_block(&t.name, &CLOSED_PHASES));
        s.err.push_str(&t.extra_progress);
    }
    for t in theories {
        if let Some(p) = &t.payload {
            s.out.push_str(p);
        }
    }
    let summaries: Vec<Summary> = theories.iter().map(|t| t.summary.clone()).collect();
    s.out.push_str(&render_summary(&summaries));
    s
}

/// A theory under `--parse-only`: its name (for the single progress marker) and
/// its opaque payload.
#[derive(Debug, Clone)]
pub struct LoadedTheory {
    pub name: String,
    pub payload: String,
}

/// A `--parse-only` run: stderr carries one `Theory loaded` marker per theory (no
/// preamble); stdout carries the concatenated payloads (no summary block).
pub fn frame_parse_only(theories: &[LoadedTheory]) -> Streams {
    let mut s = Streams::default();
    for t in theories {
        s.err.push_str(&progress_line(&t.name, Phase::Loaded));
        s.out.push_str(&t.payload);
    }
    s
}

/// A `variants` run: stdout carries the variant payload; stderr carries only the
/// maude preamble (no progress markers, no summary).
pub fn frame_variants(maude: &MaudeInfo, payload: &str) -> Streams {
    Streams { out: payload.to_string(), err: maude_preamble(maude) }
}

//! Incremental (streaming) emission of the batch output.
//!
//! The assembled model in [`super::framing`] builds both complete [`Streams`]
//! and hands them back at the end. A consumer that wants output to appear *as
//! the prover runs* — progress markers and payloads flushed while later theories
//! are still being processed — needs to drive emission event-by-event instead.
//!
//! This module provides that drive surface. A [`Sink`] is the consumer's byte
//! destination, tagged by [`Stream`]; the consumer decides when (or whether) to
//! flush after each call. [`BatchEmitter`] defines *what* bytes are produced and
//! *in what per-stream order* — nothing here forces buffering or a final barrier
//! except the "summary of summaries" block, which is inherently a single trailing
//! block over every theory and so is buffered until [`BatchEmitter::finish`].
//!
//! The per-stream byte total is identical to the assembled model: both paths
//! emit, on stderr, the maude preamble then each theory's progress in order, and,
//! on stdout, each printed payload in order then the one combined summary. The two
//! streams interleave differently in wall-clock time (that is the point of
//! streaming), but each stream's byte sequence is unchanged. The equivalence is
//! exercised by the crate's tests via [`drive_batch`].

use super::framing::{progress_line, render_summary, BatchTheory, Phase, Summary, CLOSED_PHASES};
use super::stream::{Stream, Streams};
use super::version::{maude_preamble, MaudeInfo};

/// A byte destination the incremental emitter writes to, tagged by which standard
/// stream the bytes belong on. Implementors choose flush timing: a
/// flush-per-call sink yields true line-by-line streaming; a buffering sink
/// coalesces. The emitter never assumes either.
pub trait Sink {
    /// Hand `text` to the destination for `stream`. Called once per emitted chunk
    /// in emission order.
    fn emit(&mut self, stream: Stream, text: &str);
}

/// A [`Sink`] that accumulates into an in-memory [`Streams`]. Useful for tests
/// and for callers that want the fully assembled result from the streaming path.
#[derive(Debug, Clone, Default)]
pub struct StreamCollector {
    pub streams: Streams,
}

impl Sink for StreamCollector {
    fn emit(&mut self, stream: Stream, text: &str) {
        self.streams.push(stream, text);
    }
}

/// Drives incremental emission of a closed batch run into a [`Sink`].
///
/// Lifecycle: [`begin`](Self::begin) emits the preamble; then, per theory as the
/// engine produces it, call [`progress`](Self::progress) for each phase reached,
/// [`extra_progress`](Self::extra_progress) for any engine lines after the last
/// phase, [`payload`](Self::payload) when the theory's pretty-print is ready, and
/// [`record_summary`](Self::record_summary) once its verdict is known; finally
/// [`finish`](Self::finish) emits the combined summary. The consumer may flush its
/// sink at any point between calls.
pub struct BatchEmitter<'a, S: Sink> {
    sink: &'a mut S,
    summaries: Vec<Summary>,
}

impl<'a, S: Sink> BatchEmitter<'a, S> {
    /// Start a batch run: emit the three-line maude readiness preamble on stderr.
    pub fn begin(sink: &'a mut S, maude: &MaudeInfo) -> Self {
        sink.emit(Stream::Err, &maude_preamble(maude));
        BatchEmitter { sink, summaries: Vec::new() }
    }

    /// Emit one `[Theory <name>] <phase>` progress marker on stderr.
    pub fn progress(&mut self, theory: &str, phase: Phase) {
        self.sink.emit(Stream::Err, &progress_line(theory, phase));
    }

    /// Emit all five closed-theory progress markers for `theory`, in order.
    pub fn closed_phases(&mut self, theory: &str) {
        for phase in CLOSED_PHASES {
            self.progress(theory, phase);
        }
    }

    /// Emit further engine progress lines on stderr, verbatim (already
    /// newline-terminated), e.g. the `[Saturating Sources] …` lines a `--prove`
    /// run appends after a theory's `Theory closed` marker. A no-op for `""`.
    pub fn extra_progress(&mut self, text: &str) {
        if !text.is_empty() {
            self.sink.emit(Stream::Err, text);
        }
    }

    /// Emit a theory's pretty-printed payload on stdout. Pass `None` when the
    /// theory was written to an output file instead (nothing is emitted).
    pub fn payload(&mut self, payload: Option<&str>) {
        if let Some(p) = payload {
            self.sink.emit(Stream::Out, p);
        }
    }

    /// Record this theory's contribution to the trailing summary. Buffered until
    /// [`finish`](Self::finish), because the "summary of summaries" is one block
    /// over every theory.
    pub fn record_summary(&mut self, summary: Summary) {
        self.summaries.push(summary);
    }

    /// Emit the combined "summary of summaries" block on stdout, closing the run.
    pub fn finish(self) {
        self.sink.emit(Stream::Out, &render_summary(&self.summaries));
    }
}

/// Convenience driver: stream a whole `&[BatchTheory]` into `sink` in the natural
/// per-theory order (preamble; then, per theory, its closed phases, extra
/// progress, payload, and recorded summary; then the combined summary). Produces
/// per-stream bytes identical to [`super::framing::frame_batch`] on the same
/// inputs — the streaming/assembled equivalence the interop requirement asks for.
pub fn drive_batch<S: Sink>(sink: &mut S, maude: &MaudeInfo, theories: &[BatchTheory]) {
    let mut e = BatchEmitter::begin(sink, maude);
    for t in theories {
        e.closed_phases(&t.name);
        e.extra_progress(&t.extra_progress);
        e.payload(t.payload.as_deref());
        e.record_summary(t.summary.clone());
    }
    e.finish();
}

